import { Navigate } from "react-router-dom";

export default function protectedRoute({ children }) {
  const isAuthenticated = localStorage.getItem("loggedIn") === true;

  if (!isAuthenticated) {
    return <Navigate to = "/Login" replace />;
  }

}
